import React, { useState } from "react";
import "./login.css";
import { login } from "../../services/userService";
import { setCookie } from "../../helper/cookies";
import { NavLink, useNavigate } from "react-router-dom";
import { useDispatch } from "react-redux";
import { checkLogin } from "../../actions/login";

const LoginComponent = () => {
  const [errorMessage, setErrorMessage] = useState(""); // Quản lý thông báo lỗi
  const [loginmodal, setlogin] = useState(false); // Quản lý trạng thái modal
  const navigate = useNavigate();
  const dispatch = useDispatch();

  const handleClose = () => {
    setlogin(false); // Đóng modal
  };

  const handlelogin = () => {
    setlogin(true); // Mở modal
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const username = e.target.username.value.trim();
    const password = e.target.password.value.trim();

    if (!username || !password) {
      setErrorMessage("Vui lòng nhập tên đăng nhập và mật khẩu!");
      return;
    }

    try {
      const response = await login(username, password);
      console.log("Login response:", response);

      if (response && response.length > 0) {
        const user = response[0];
        console.log("User data:", user);

        // Lưu thông tin xác thực
        setCookie("username", user.username, 1); // Lưu cookie trong 1 ngày
        setCookie("password", user.password, 1);
        localStorage.setItem("user", JSON.stringify(user)); // Lưu user vào localStorage

        dispatch(checkLogin(true)); // Cập nhật trạng thái đăng nhập
        navigate("/"); // Chuyển hướng về trang chủ
      } else {
        setErrorMessage("Sai tên đăng nhập hoặc mật khẩu!");
      }
    } catch (error) {
      console.error("Login error:", error.message);
      setErrorMessage("Đăng nhập thất bại. Vui lòng thử lại!");
    }
  };

  return (
    <>
      {/* Mở form đăng nhập */}
      {!loginmodal && (
        <div onClick={handlelogin} className="btn-open-login">
          Đăng nhập
        </div>
      )}

      {/* Hiển thị modal đăng nhập */}
      {loginmodal && (
        <div className="general">
          <div className="register-form">
            <h2>Đăng nhập</h2>
            {errorMessage && <p className="error-message">{errorMessage}</p>}
            <form onSubmit={handleSubmit}>
              <input
                type="text"
                name="username"
                placeholder="Tên đăng nhập"
                required
              />

              <input
                type="password"
                name="password"
                placeholder="Mật khẩu"
                required
              />

              <button type="submit" className="btn">
                Đăng nhập
              </button>
              <NavLink to="/">
                <button
                  onClick={handleClose}
                  type="button"
                  className="btn-close"
                >
                  Đóng
                </button>
              </NavLink>
            </form>
          </div>
        </div>
      )}
    </>
  );
};

export default LoginComponent;
